236	// Validate checks a command against tier rules.
237	// It returns an error if the command is hard-blocked or if it
238	// requires a higher tier than what was requested.
239	func Validate(command string, requestedTier int) error {
240		if disallowedDockerCompose(command) {
241			return errors.New("docker compose command is not in the allowlist")
242		}
243	
244		// 1. Hard-block check — always fails regardless of tier
245		for _, re := range hardBlocked {
246			if re.MatchString(command) {
247				return errors.New("command is hard-blocked: " + re.String())
248			}
249		}
250	
251		if hasActualDockerCommand(command) {
252			if requestedTier == TierRead {
253				if !dockerInvocationsAllowed(command, allowedReadDockerCommands) {
254					return errors.New("docker read command is not in the allowlist")
255				}
256			} else if requestedTier >= TierService {
257				if !matchesAny(command, allowedServiceCommands) && !dockerInvocationsAllowed(command, allowedServiceCommands) {
258					return errors.New("service command is not in the allowlist")
259				}
260			}
261		}
262	
263		// 2. Tier 1: must be read-only
264		if requestedTier == TierRead {
265			for _, re := range writePatterns {
266				if re.MatchString(command) {
267					return errors.New("command requires tier 2 or higher (detected write pattern)")
268				}
269			}
270			if hasRealOutputRedirect(command) {
271				return errors.New("command requires tier 2 or higher (detected write pattern)")
272			}
273		}
274	
275		// 3. Tier 2: may be a service op but must not touch user files
276		if requestedTier == TierService {
277			if strings.Contains(command, "/volume1/") && !strings.Contains(command, "/volume1/docker/synology-monitor-agent") {
278				return errors.New("tier 2 commands may not touch user data paths")
279			}
280			for _, re := range filePatterns {
281				if re.MatchString(command) {
282					return errors.New("command touches user data and requires tier 3")
283				}
284			}
285		}
286	
287		return nil
288	}
