290	// ClassifyTier returns the minimum tier required for a command.
291	// The caller (web app issue agent) uses this to decide whether to
292	// auto-execute (tier 1) or prompt for approval (tier 2/3).
293	func ClassifyTier(command string) int {
294		if disallowedDockerCompose(command) {
295			return -1
296		}
297		for _, re := range hardBlocked {
298			if re.MatchString(command) {
299				return -1 // never
300			}
301		}
302		isWrite := false
303		for _, re := range writePatterns {
304			if re.MatchString(command) {
305				isWrite = true
306				break
307			}
308		}
309		if !isWrite {
310			isWrite = hasRealOutputRedirect(command)
311		}
312		if !isWrite {
313			return TierRead
314		}
315		for _, re := range filePatterns {
316			if re.MatchString(command) {
317				return TierFile
318			}
319		}
320		return TierService
321	}
