323	// IsHardBlocked returns true if the command can never be executed.
324	func IsHardBlocked(command string) bool {
325		if disallowedDockerCompose(command) {
326			return true
327		}
328		for _, re := range hardBlocked {
329			if re.MatchString(command) {
330				return true
331			}
332		}
333		return false
334	}
