336	// BlockExplanation returns a client-facing reason a command is hard-blocked.
337	// Unlike Summary (which echoes the command), it states WHY, that the block is
338	// permanent and stateless, and what to do instead. This is the only signal an
339	// MCP session receives on a refusal — without it, sessions misread the block as
340	// a "rate limit" or "session degradation" and give up. Returns "" if the command
341	// is not hard-blocked.
342	func BlockExplanation(command string) string {
343		if !IsHardBlocked(command) {
344			return ""
345		}
346		// This guard is stateless and pure: the same command is refused identically on
347		// every call. It is not a per-session quota and not a degradation symptom.
348		const footer = " This block is permanent and stateless — it is NOT a rate limit, quota, or session-degradation symptom, and it fired on the command pattern alone. Retrying it or starting a fresh session will return the exact same result; change the command instead."
349	
350		switch {
351		case driveRecursiveGrepA.MatchString(command), driveRecursiveGrepB.MatchString(command):
352			return "Recursive grep against a Synology internal data store (@synologydrive / @SynologyDriveShareSync / the SynologyDrive package dir) is blocked: these hold millions of opaque objects and one such grep ran 4d11h on production before it was caught. Do this instead: grep a specific named log file non-recursively (e.g. @synologydrive/log/*.log or syncfolder.log), or query the monitoring database for historical data." + footer
353		case matchesAny(command, []*regexp.Regexp{
354			regexp.MustCompile(`(?i)\b(mkfs|fdisk|parted|wipefs|flash_eraseall|nandwrite)\b`),
355			regexp.MustCompile(`(?i)\bdd\b.*\b(if=|of=/dev/|of=/proc/)`),
356			regexp.MustCompile(`(?i)\bmdadm\s+--fail\b`),
357			regexp.MustCompile(`(?i)\bhdparm\b`),
358		}):
359			return "This is a destructive disk/firmware operation that could brick the NAS or destroy an array, so it is blocked at every tier. There is no safe way to run it through this interface — use the DSM UI for planned maintenance." + footer
360		case matchesAny(command, []*regexp.Regexp{
361			regexp.MustCompile(`(?i)\b(shutdown|reboot|poweroff|halt)\b`),
362			regexp.MustCompile(`(?i)\bsystemctl\s+(poweroff|halt|reboot)\b`),
363		}):
364			return "Powering off or rebooting the NAS is blocked here — do planned maintenance from the DSM UI so the shutdown is graceful." + footer
365		case matchesAny(command, []*regexp.Regexp{
366			regexp.MustCompile(`(?i)\b(useradd|userdel|usermod|groupadd|groupdel)\b`),
367			regexp.MustCompile(`(?i)\bpasswd\s+\S`),
368		}):
369			return "User/group account changes are blocked to avoid locking out admins — manage accounts in DSM Control Panel." + footer
370		case matchesAny(command, []*regexp.Regexp{
371			regexp.MustCompile(`(?i)\b(apt(-get)?|opkg)\s+(install|remove|purge)\b`),
372			regexp.MustCompile(`(?i)\bpip\s+install\b`),
373			regexp.MustCompile(`(?i)\bnpm\s+install\s+-g\b`),
374			regexp.MustCompile(`(?i)\bsynopkg\s+(install|uninstall|remove)\b`),
375		}):
376			return "Installing or removing packages on the host is blocked — it would mutate the NAS OS outside the monitored deploy path." + footer
377		case matchesAny(command, []*regexp.Regexp{
378			regexp.MustCompile(`(?i)\bdocker\s+(run|create|cp|plugin|network|volume|context|swarm|stack|builder|buildx)\b`),
379		}):
380			return "This docker subcommand grants host-level control and is outside the small monitor-stack allowlist, so it is blocked. Read-only docker (ps/stats/inspect/logs) and the monitor-agent compose ops are permitted." + footer
381		default:
382			return "This command matches a permanent safety rule (it could destroy data, modify the OS/firmware, manage accounts, or take the NAS offline)." + footer
383		}
384	}
