386	// Summary returns a human-readable description of what a command does,
387	// used for building the approval preview shown to the operator.
388	func Summary(command string) string {
389		cmd := strings.TrimSpace(command)
390		if strings.HasPrefix(cmd, "cat ") {
391			return "Read file: " + strings.TrimPrefix(cmd, "cat ")
392		}
393		if strings.Contains(cmd, "synopkg restart") {
394			return "Restart Synology package"
395		}
396		if strings.Contains(cmd, "docker") && strings.Contains(cmd, "restart") {
397			return "Restart Docker container"
398		}
399		if strings.Contains(cmd, "mv ") && strings.Contains(cmd, ".old") {
400			return "Rename file to .old (quarantine)"
401		}
402		return cmd
403	}
