414	func disallowedDockerCompose(command string) bool {
415		cmd := strings.TrimSpace(command)
416		if !strings.Contains(cmd, "docker compose") {
417			return false
418		}
419		allowed := []string{
420			"docker compose restart",
421			"docker compose stop",
422			"docker compose up -d",
423			"docker compose pull",
424			"docker compose build --pull",
425		}
426		for _, prefix := range allowed {
427			if strings.Contains(cmd, prefix) {
428				return false
429			}
430		}
431		return true
432	}
